func FileDescriptorSet() *descriptorpb.FileDescriptorSet {
	// We just need ONE of the service names to look up the FileDescriptorSet.
	ret, err := discovery.GetDescriptorSet("luci.milo.v1.MiloInternal")
	if err != nil {
		panic(err)
	}
	return ret
}
